import com.amazonaws.auth.AWSCredentialsProviderChain
import com.amazonaws.services.s3.AmazonS3ClientBuilder

object MyService {
  def main(args: Array[String]): Unit = {
    // Create a credentials provider chain
    val credentialsProvider = AWSCredentialsProviderChain.getInstance()

    // Build an Amazon S3 client using the credentials provider
    val s3Client = AmazonS3ClientBuilder.standard()
      .withCredentials(credentialsProvider)
      .build()

    // Use the S3 client to perform some AWS operations
    val objectListing = s3Client.listObjects("my-bucket")
    for (objectSummary <- objectListing.getObjectSummaries()) {
      println(objectSummary.getKey())
    }
  }
}